Nuc(T) = { x ∈ Rⁿ | T(x) = 0 } = { x | Ax = 0 }
Im(T) = { T(x) | x ∈ Rⁿ } = { Ax | x ∈ Rⁿ }

// Geometricamente:
// Nuc(T): o que T 'colapsa' para 0
// Im(T): o que T 'alcança' em Rᵐ

// Nomes alternativos:
// Nuc(T) = espaço nulo de A = Nul(A)
// Im(T) = espaço coluna de A = Col(A)

Teorema do Núcleo-Imagem (T: Rⁿ → Rᵐ):

  dim(Nuc T) + dim(Im T) = n

  nullidade(A) + posto(A) = n (nº de colunas)

// Consequências:
// T injetiva ⟺ Nuc(T) = {0} ⟺ posto(A) = n
// T sobrejetiva ⟺ Im(T) = Rᵐ ⟺ posto(A) = m
